const items = $input.all();

// Separar ranking y tendencias
const ranking = items.filter(i => i.json.pedidos_mes !== undefined).map(i => i.json);
const tendencias = items.filter(i => i.json.crecimiento_pct !== undefined).map(i => i.json);

// Colores por categoría
const colores = {
  'Pizza':'#7F77DD',
  'Sushi':'#1D9E75',
  'Burger':'#EF9F27',
  'Hamburguesa':'#EF9F27',
  'Mexicana':'#D85A30',
  'Saludable':'#378ADD'
};

// Top 5 para la gráfica
const top5 = ranking.slice(0, 5);
const barLabels = JSON.stringify(top5.map(r => r.nombre));
const barPedidos = JSON.stringify(top5.map(r => r.pedidos_mes));
const barColors = JSON.stringify(top5.map(r => colores[r.categoria] || '#888'));

// Filas tabla ranking
const filas = ranking.map((r, i) => {
  const medalla = i === 0 ? '🥇' : i === 1 ? '🥈' : i === 2 ? '🥉' : `${i+1}`;
  const color = colores[r.categoria] || '#888';
  const estrellas = '★'.repeat(Math.round(r.calificacion)) + '☆'.repeat(5 - Math.round(r.calificacion));
  return `<tr>
    <td style="font-size:18px;text-align:center">${medalla}</td>
    <td><strong>${r.nombre}</strong><br><span style="font-size:11px;color:#aaa">${r.ciudad}</span></td>
    <td><span style="background:${color}22;color:${color};padding:2px 8px;border-radius:99px;font-size:11px;font-weight:600">${r.categoria}</span></td>
    <td style="color:#f5a623">${estrellas} <span style="color:#aaa;font-size:11px">${r.calificacion}</span></td>
    <td style="font-weight:600">${parseInt(r.pedidos_mes).toLocaleString('es-CO')}</td>
    <td style="color:#1D9E75">${r.tiempo_entrega_min} min</td>
  </tr>`;
}).join('');

// Filas tendencias
const filasT = tendencias.map(t => {
  const pct = parseFloat(t.crecimiento_pct);
  const color = pct >= 0 ? '#1D9E75' : '#E24B4A';
  const arrow = pct >= 0 ? '▲' : '▼';
  return `<tr>
    <td><strong>${t.nombre}</strong></td>
    <td>${parseInt(t.pedidos_semana_anterior).toLocaleString('es-CO')}</td>
    <td>${parseInt(t.pedidos_esta_semana).toLocaleString('es-CO')}</td>
    <td style="color:${color};font-weight:700">${arrow} ${Math.abs(pct)}%</td>
  </tr>`;
}).join('');

const ahora = new Date().toLocaleString('es-CO', {
  dateStyle: 'long', timeStyle: 'short', timeZone: 'America/Bogota'
});

const html = `<!DOCTYPE html>
<html lang="es">
<head>
  <meta charset="utf-8">
  <meta name="viewport" content="width=device-width,initial-scale=1">
  <title>Ranking de Restaurantes</title>
  <meta http-equiv="refresh" content="300">
  <script src="https://cdn.jsdelivr.net/npm/chart.js"><\/script>
  <style>
    *{box-sizing:border-box;margin:0;padding:0}
    body{font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',sans-serif;background:#f4f3fb;color:#1a1a2e;min-height:100vh}
    header{background:#7F77DD;padding:24px 32px;color:#fff}
    header h1{font-size:24px;font-weight:700;letter-spacing:-.3px}
    header p{font-size:13px;opacity:.75;margin-top:4px}
    .container{max-width:960px;margin:0 auto;padding:28px 20px}
    .grid-2{display:grid;grid-template-columns:1fr 1fr;gap:20px;margin-bottom:20px}
    @media(max-width:640px){.grid-2{grid-template-columns:1fr}}
    .card{background:#fff;border-radius:14px;padding:22px 24px;border:0.5px solid rgba(0,0,0,0.07)}
    .card-title{font-size:12px;font-weight:700;color:#aaa;text-transform:uppercase;letter-spacing:.08em;margin-bottom:14px}
    .kpi-val{font-size:28px;font-weight:700;color:#7F77DD;line-height:1.2}
    .kpi-val.green{color:#1D9E75}
    .kpi-sub{font-size:12px;color:#aaa;margin-top:4px}
    canvas{width:100%!important}
    table{width:100%;border-collapse:collapse;font-size:13px}
    th{color:#aaa;font-weight:500;padding:8px 10px;border-bottom:1px solid #f0f0f0;text-align:left;font-size:11px;text-transform:uppercase;letter-spacing:.05em}
    td{padding:10px 10px;border-bottom:1px solid #fafafa;vertical-align:middle}
    tr:last-child td{border-bottom:none}
    tr:hover td{background:#faf9ff}
    .footer{text-align:center;font-size:11px;color:#bbb;padding:20px;margin-top:8px}
    .live-dot{display:inline-block;width:7px;height:7px;background:#1D9E75;border-radius:50%;margin-right:5px;animation:pulse 2s infinite}
    @keyframes pulse{0%,100%{opacity:1}50%{opacity:.3}}
  <\/style>
<\/head>
<body>
  <header>
    <h1>Ranking de Restaurantes</h1>
    <p><span class="live-dot"><\/span>Actualizado: ${ahora}<\/p>
  <\/header>

  <div class="container">
    <div class="grid-2">
      <div class="card">
        <div class="card-title">Restaurante #1 esta semana<\/div>
        <div class="kpi-val">${ranking[0]?.nombre || '—'}<\/div>
        <div class="kpi-sub">${parseInt(ranking[0]?.pedidos_mes || 0).toLocaleString('es-CO')} pedidos este mes<\/div>
      <\/div>
      <div class="card">
        <div class="card-title">Mayor crecimiento semanal<\/div>
        <div class="kpi-val green">${tendencias[0]?.nombre || '—'}<\/div>
        <div class="kpi-sub">▲ ${tendencias[0]?.crecimiento_pct || 0}% vs semana anterior<\/div>
      <\/div>
    <\/div>

    <div class="card" style="margin-bottom:20px">
      <div class="card-title">Top 5 — pedidos del mes<\/div>
      <canvas id="barChart" height="90"><\/canvas>
    <\/div>

    <div class="card" style="margin-bottom:20px">
      <div class="card-title">Ranking completo<\/div>
      <table>
        <tr><th>#<\/th><th>Restaurante<\/th><th>Categoría<\/th><th>Calificación<\/th><th>Pedidos<\/th><th>Entrega<\/th><\/tr>
        ${filas}
      <\/table>
    <\/div>

    <div class="card">
      <div class="card-title">Tendencias — crecimiento semana a semana<\/div>
      <table>
        <tr><th>Restaurante<\/th><th>Sem. anterior<\/th><th>Esta semana<\/th><th>Cambio<\/th><\/tr>
        ${filasT}
      <\/table>
    <\/div>
  <\/div>

  <div class="footer">Construido con n8n + PostgreSQL · Ranking Restaurantes<\/div>

  <script>
    new Chart(document.getElementById('barChart'), {
      type: 'bar',
      data: {
        labels: ${barLabels},
        datasets: [{
          label: 'Pedidos del mes',
          data: ${barPedidos},
          backgroundColor: ${barColors},
          borderRadius: 8,
          borderSkipped: false
        }]
      },
      options: {
        responsive: true,
        plugins: { legend: { display: false } },
        scales: {
          y: { grid: { color: 'rgba(0,0,0,0.04)' }, ticks: { color: '#aaa', font: { size: 11 } } },
          x: { grid: { display: false }, ticks: { color: '#555', font: { size: 11 } } }
        }
      }
    });
  <\/script>
<\/body>
<\/html>`;

return [{ json: { html } }];
